import { useRef } from 'react';

import { ORIENTATION } from '../../../../../constants.js';
import { useOrientation } from '../../context/RangeLegendOrientationContext.js';
import { useScale } from '../../context/RangeLegendScaleContext.js';
import { useLegendFormattedLabels } from '../../hooks/use-legend-formatted-labels.js';
import type { InternalRangeItem } from '../../types/range-legend.internal.js';
import { RangeLegendSegmentsItem } from '../RangeLegendSegmentsItem.js';
import { legendSvg } from './RangeLegendSegments.sty.js';

interface RangeLegendSegmentsProps {
  items: InternalRangeItem[];
  minValue?: number;
  maxValue?: number;
}

export const RangeLegendSegments = (props: RangeLegendSegmentsProps) => {
  const { items } = props;

  const svgRef = useRef<SVGSVGElement>(null);

  const { scale } = useScale();
  const { orientation } = useOrientation();
  const reversedScale = orientation === ORIENTATION.Vertical;
  const internalRangeItems = useLegendFormattedLabels(items);

  return (
    <svg
      ref={svgRef}
      className={legendSvg({
        isHorizontal: orientation === ORIENTATION.Horizontal,
      })}
      role="presentation"
      data-testid="range-legend-segments"
    >
      {internalRangeItems.map((item) => {
        const startPosition = scale(reversedScale ? item.to : item.from);
        const endPosition = scale(reversedScale ? item.from : item.to);
        const segmentSize = endPosition - startPosition;

        return (
          <RangeLegendSegmentsItem
            key={`segment-'${item.from}-${item.to}`}
            item={item}
            segmentSize={segmentSize}
            startPosition={startPosition}
          />
        );
      })}
    </svg>
  );
};
